private OperationRule setMetadata(OperationRule rule, Swagger metadata, List<String> scopeValidators, String scope) {
    Model model = getModelFromSwagger(rule, metadata);
    if (model != null) {
        Property property = model.getProperties().get(rule.getAttributeName());

        if (property != null) {
            Map<String, Object> vendorExtensions = property.getVendorExtensions();
            rule.setModel(model);

            if (vendorExtensions.containsKey(ApiMetadataExtensions.OpenLValidator.NAME)) {
                String[] validatorsArray = (String[]) vendorExtensions.get(ApiMetadataExtensions.OpenLValidator.NAME);
                List<String> validators = new ArrayList<>(Arrays.asList(validatorsArray));

                if (StringUtils.isNotBlank(scope)) {
                    validators.removeIf(scopeValidator -> {
                        return validators.contains(scopeValidator) || validators.contains(scopeValidator.replace("For" + scope, ""));
                    });
                }

                rule.setValidators(validators);
            }

            if (vendorExtensions.containsKey(ApiMetadataExtensions.OpenLDefaultValue.NAME)) {
                String defaultValue = (String) vendorExtensions.get(ApiMetadataExtensions.OpenLDefaultValue.NAME);
                rule.setDefaultValue(defaultValue);
            }

            if (vendorExtensions.containsKey(ApiMetadataExtensions.OpenLValueRange.NAME)) {
                LinkedHashMap<String, String> valueRange = (LinkedHashMap<String, String>) vendorExtensions.get(ApiMetadataExtensions.OpenLValueRange.NAME);
                valueRange.remove(StringUtils.EMPTY);

                if (CollectionUtils.isNotEmpty(valueRange.keySet()) && rule.getAttributeValue() != null) {
                    rule.setValueRange(valueRange.keySet());
                }
            }

            if (vendorExtensions.containsKey(ApiMetadataExtensions.OpenLApplicable.NAME)) {
                boolean applicable = (Boolean) vendorExtensions.get(ApiMetadataExtensions.OpenLApplicable.NAME);
                rule.setApplicable(applicable);
            }
        }
    }

    return rule;
}
